// src/pages/FarmDetail.js
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css'; // Sá»­ dá»„ng láșĄi CSS cho form
import './Manager.css'; // Sá»­ dá»„ng láșĄi CSS cho báșŁng (náșżu báșĄn cĂł cĂĄc style báșŁng riĂȘng cho activities)

function FarmDetail() {
  const { farmId } = useParams(); // Láș„y farmId tá»« URL
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role'); // Láș„y vai trĂČ ngÆ°á»i dĂčng Äá» kiá»m tra quyá»n

  const [farm, setFarm] = useState(null);
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // State cho form nháș­p báșŁn ghi theo dĂ”i
  const [activityFormData, setActivityFormData] = useState({
    speciesName: '', // TĂȘn loĂ i - Giá» ÄĂąy sáșœ ÄÆ°á»Łc chá»n tá»« dropdown á» Äáș§u trang
    date: '',        // NgĂ y ghi nháș­n
    totalIndividuals: 0, // Tá»ng sá» cĂĄ thá» - GiĂĄ trá» nĂ y sáșœ khĂŽng ÄÆ°á»Łc nháș­p qua UI form ná»Ża
    currentStatus: { // currentStatus váș«n ÄÆ°á»Łc giá»Ż trong state Äá» gá»­i lĂȘn backend
      parents: { male: 0, female: 0 },
      otherIndividuals: { male: 0, female: 0, unidentified: 0 }
    },
    increase: {
      parents: { male: 0, female: 0 },
      otherIndividuals: { male: 0, female: 0, unidentified: 0 }
    },
    decrease: {
      parents: { male: 0, female: 0 },
      otherIndividuals: { male: 0, female: 0, unidentified: 0 }
    },
    reasonForChange: '',
    verifiedBy: '', // TrÆ°á»ng nĂ y sáșœ khĂŽng cĂČn ÄÆ°á»Łc nháș­p qua UI form ná»Ża
  });

  // HĂ m fetch chi tiáșżt cÆĄ sá» gĂąy nuĂŽi vĂ  cĂĄc báșŁn ghi theo dĂ”i
  const fetchFarmDetails = async () => {
    setLoading(true);
    setError('');
    setMessage('');
    try {
      // Láș„y thĂŽng tin chi tiáșżt cÆĄ sá» nuĂŽi
      const resFarm = await axios.get(`http://localhost:10000/api/farms/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setFarm(resFarm.data);

      // Náșżu cĂł dá»Ż liá»u loĂ i, Äáș·t giĂĄ trá» máș·c Äá»nh cho speciesName trong form hoáșĄt Äá»ng
      if (resFarm.data.species && resFarm.data.species.length > 0) {
        setActivityFormData(prev => ({
          ...prev,
          speciesName: resFarm.data.species[0].name // Äáș·t loĂ i Äáș§u tiĂȘn lĂ m máș·c Äá»nh
        }));
      }

      // Láș„y cĂĄc báșŁn ghi theo dĂ”i biáșżn Äá»ng cho cÆĄ sá» nĂ y
      const resActivities = await axios.get(`http://localhost:10000/api/farm-activities/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setActivities(resActivities.data);

    } catch (err) {
      console.error('Lá»i khi táșŁi chi tiáșżt cÆĄ sá» nuĂŽi hoáș·c cĂĄc báșŁn ghi theo dĂ”i:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'KhĂŽng thá» táșŁi chi tiáșżt cÆĄ sá» gĂąy nuĂŽi hoáș·c cĂĄc báșŁn ghi theo dĂ”i.');
      // Chuyá»n hÆ°á»ng náșżu khĂŽng tĂŹm tháș„y hoáș·c khĂŽng cĂł quyá»n
      if (err.response && (err.response.status === 401 || err.response.status === 403 || err.response.status === 404)) {
        navigate('/admin/farms');
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    console.log("FarmDetail.js: useEffect is running!"); // ThĂȘm console log Äá» kiá»m tra
    if (farmId && token) {
      fetchFarmDetails();
    } else if (!farmId) {
      setError('KhĂŽng cĂł ID cÆĄ sá» nuĂŽi Äá» xem chi tiáșżt.');
      setLoading(false);
    } else if (!token) {
      setError('BáșĄn cáș§n ÄÄng nháș­p Äá» xem chi tiáșżt cÆĄ sá» nuĂŽi.');
      setLoading(false);
      navigate('/');
    }
  }, [farmId, token, navigate]); // ThĂȘm navigate vĂ o dependency array

  const handleActivityFormChange = (e) => {
    const { name, value } = e.target;
    let newFormData = { ...activityFormData };

    // Xá»­ lĂœ cĂĄc trÆ°á»ng ÄÆĄn giáșŁn trá»±c tiáșżp (speciesName, date, reasonForChange)
    if (['speciesName', 'date', 'reasonForChange'].includes(name)) { // verifiedBy ÄĂŁ bá» loáșĄi bá» khá»i ÄĂąy
      newFormData = {
        ...newFormData,
        [name]: value,
      };
    }
    else {
      // Xá»­ lĂœ cĂĄc trÆ°á»ng nested (increase, decrease)
      const [mainField, subField, prop] = name.split('.');
      newFormData = {
        ...newFormData,
        [mainField]: {
          ...newFormData[mainField],
          [subField]: {
            ...newFormData[mainField][subField],
            [prop]: parseInt(value, 10) || 0,
          },
        },
      };
    }
    setActivityFormData(newFormData);
  };

  const handleAddActivity = async (e) => {
    e.preventDefault();
    setMessage('');
    setError('');
    try {
      // ÄáșŁm báșŁo farmId ÄÆ°á»Łc gá»­i cĂčng vá»i dá»Ż liá»u form
      const dataToSend = {
        ...activityFormData,
        farm: farmId, // LiĂȘn káșżt báșŁn ghi theo dĂ”i vá»i farmId
      };
      const res = await axios.post(`http://localhost:10000/api/farm-activities`, dataToSend, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setMessage('ThĂȘm báșŁn ghi theo dĂ”i thĂ nh cĂŽng!');
      // Cáș­p nháș­t láșĄi danh sĂĄch activities
      setActivities(prevActivities => [...prevActivities, res.data]);
      // Reset form, giá»Ż láșĄi speciesName náșżu nĂł ÄĂŁ ÄÆ°á»Łc chá»n á» trĂȘn
      setActivityFormData(prev => ({
        ...prev,
        date: '',
        totalIndividuals: 0, // Reset vá» 0
        currentStatus: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        increase: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        decrease: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        reasonForChange: '',
        verifiedBy: '', // Reset vá» rá»ng
      }));
    } catch (err) {
      console.error('Lá»i khi thĂȘm báșŁn ghi theo dĂ”i:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Lá»i khi thĂȘm báșŁn ghi theo dĂ”i.');
    }
  };

  const handleDeleteActivity = async (activityId) => {
    if (window.confirm('BáșĄn cĂł cháșŻc cháșŻn muá»n xĂła báșŁn ghi nĂ y?')) {
      setMessage('');
      setError('');
      try {
        await axios.delete(`http://localhost:10000/api/farm-activities/${activityId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        setMessage('BáșŁn ghi ÄĂŁ ÄÆ°á»Łc xĂła thĂ nh cĂŽng.');
        // Cáș­p nháș­t láșĄi danh sĂĄch activities sau khi xĂła
        setActivities(prevActivities => prevActivities.filter(act => act._id !== activityId));
      } catch (err) {
        console.error('Lá»i khi xĂła báșŁn ghi theo dĂ”i:', err.response?.data || err.message);
        setError(err.response?.data?.message || 'Lá»i khi xĂła báșŁn ghi theo dĂ”i.');
      }
    }
  };


  if (loading) {
    return <div className="form-container"><p>Äang táșŁi dá»Ż liá»u...</p></div>;
  }

  if (error) {
    return (
      <div className="form-container">
        <p style={{ color: 'red' }}>Lá»i: {error}</p>
        <button onClick={() => navigate('/admin/farms')}>Quay láșĄi danh sĂĄch</button>
      </div>
    );
  }

  if (!farm) {
    return (
      <div className="form-container">
        <p style={{ color: 'orange' }}>KhĂŽng tĂŹm tháș„y thĂŽng tin cÆĄ sá» gĂąy nuĂŽi.</p>
        <button onClick={() => navigate('/admin/farms')}>Quay láșĄi danh sĂĄch</button>
      </div>
    );
  }

  return (
    <div className="form-container">
      {/* ThĂȘm CSS tĂčy chá»nh vĂ o ÄĂąy */}
      <style>
        {`
        .form-section-wrapper {
          flex: 1; /* ÄáșŁm báșŁo cĂĄc pháș§n TÄng ÄĂ n/GiáșŁm ÄĂ n chia Äá»u khĂŽng gian */
          min-width: 300px; /* NgÄn khĂŽng cho chĂșng quĂĄ nhá» trĂȘn mĂ n hĂŹnh háșčp */
          padding: 3px; /* GiáșŁm padding Äá» giáșŁm khoáșŁng cĂĄch */
          box-sizing: border-box; /* ÄáșŁm báșŁo padding khĂŽng lĂ m tÄng kĂ­ch thÆ°á»c tá»ng thá» */
        }

        .form-section-row {
          display: flex;
          gap: 15px; /* GiáșŁm khoáșŁng cĂĄch giá»Ża cĂĄc input trong cĂčng má»t hĂ ng */
          margin-bottom: 3px; /* GiáșŁm khoáșŁng cĂĄch giá»Ża cĂĄc dĂČng */
          align-items: center;
        }

        /* Äiá»u chá»nh cho input trong form-group Äá» chĂșng khĂŽng bá» quĂĄ nhá» */
        .form-group input[type="number"],
        .form-group input[type="text"],
        .form-group input[type="date"],
        .form-group select { /* ThĂȘm select vĂ o ÄĂąy */
          width: 100%; /* ÄáșŁm báșŁo input chiáșżm háșżt chiá»u rá»ng cĂł thá» */
          box-sizing: border-box; /* Bao gá»m padding vĂ  border vĂ o width */
          padding: 8px 10px; /* GiáșŁm padding cho input */
        }

        /* GiáșŁm khoáșŁng cĂĄch cho h2 vĂ  h3 trong form-container */
        .form-container h2 {
          margin-bottom: 5px; /* GiáșŁm thĂȘm */
        }

        .form-container h3 {
          margin-top: 8px; /* GiáșŁm thĂȘm */
          margin-bottom: 3px; /* GiáșŁm khoáșŁng cĂĄch dÆ°á»i h3 */
        }

        /* GiáșŁm khoáșŁng cĂĄch cho cĂĄc form-group chung */
        .form-group {
            margin-bottom: 5px; /* GiáșŁm khoáșŁng cĂĄch giá»Ża cĂĄc nhĂłm form */
        }

        /* GiáșŁm khoáșŁng cĂĄch giá»Ża label vĂ  input/select */
        .form-group label {
          margin-bottom: 3px; /* GiáșŁm tá»« 5px */
        }

        /* ÄáșŁm báșŁo form-grid Äáș§u tiĂȘn trong form khĂŽng cĂł margin-top thá»«a */
        .modern-form .form-grid:first-of-type {
            margin-top: 0;
            padding-top: 0;
        }

        /* Äiá»u chá»nh khoáșŁng cĂĄch giá»Ża ĂŽ input ngĂ y thĂĄng vĂ  tiĂȘu Äá» "TÄng ÄĂ n" */
        .modern-form .form-grid .form-group:last-of-type { /* Chá»n form-group cuá»i cĂčng trong form-grid Äáș§u tiĂȘn */
            margin-bottom: 0; /* LoáșĄi bá» margin-bottom Äá» giáșŁm khoáșŁng cĂĄch */
        }
        .modern-form h4 { /* TiĂȘu Äá» h4 (TÄng ÄĂ n, GiáșŁm ÄĂ n) */
            margin-top: 5px; /* GiáșŁm margin-top */
            margin-bottom: 3px; /* GiáșŁm margin-bottom */
        }

        .modern-form .form-grid { /* KhoáșŁng cĂĄch giá»Ża cĂĄc cá»t trong form-grid */
            gap: 15px; /* GiáșŁm khoáșŁng cĂĄch giá»Ża cĂĄc cá»t */
        }
        `}
      </style>

      <h2>đïž Sá» nuĂŽi: {farm.tenCoSo}</h2>
      
      {/* ÄĂŁ thay Äá»i Äá» TĂȘn cÆĄ sá», Äá»a chá» vĂ  TĂȘn loĂ i ngang hĂ ng */}
      <div className="form-grid"> {/* Sá»­ dá»„ng form-grid Äá» táșĄo cĂĄc cá»t */}
        <div className="detail-group">
          <strong>TĂȘn cÆĄ sá»:</strong> <p>{farm.tenCoSo}</p>
        </div>
        <div className="detail-group">
          <strong>Äá»a chá»:</strong> <p>{farm.diaChi}</p>
        </div>
        <div className="form-group detail-group"> {/* ÄĂŁ di chuyá»n ĂŽ chá»n TĂȘn loĂ i lĂȘn ÄĂąy */}
          <label>TĂȘn loĂ i:</label>
          <select
            name="speciesName"
            value={activityFormData.speciesName}
